const response = $input.first().json;
const alerts = Array.isArray(response.alerts) ? response.alerts : [];

const groups = {};
const rows = [];

for (const alert of alerts) {
  const errorCode = String(alert.error_code === undefined || alert.error_code === null ? 'unknown' : alert.error_code);
  const logLevel = String(alert.log_level || 'unknown');
  const key = errorCode + '|' + logLevel;

  rows.push({
    timestamp: alert.date_generated || '',
    errorCode: errorCode,
    logLevel: logLevel,
    resourceSid: alert.resource_sid || '',
    requestUrl: alert.request_url || '',
    alertSid: alert.sid || ''
  });

  if (!groups[key]) {
    groups[key] = { errorCode: errorCode, logLevel: logLevel, count: 0, sampleMessage: '', moreInfo: alert.more_info || '' };
  }
  groups[key].count = groups[key].count + 1;
  if (!groups[key].sampleMessage) {
    groups[key].sampleMessage = String(alert.alert_text || '').slice(0, 140);
  }
}

const grouped = Object.values(groups).sort(function (a, b) { return b.count - a.count; });

const severity = {};
for (const group of grouped) {
  severity[group.logLevel] = (severity[group.logLevel] || 0) + group.count;
}

const severityLine = Object.keys(severity).sort().map(function (level) {
  return level + ': ' + severity[level];
}).join(', ');

const topLines = grouped.slice(0, 5).map(function (group) {
  return '- ' + group.errorCode + ' (' + group.logLevel + ') x' + group.count + ' ' + group.sampleMessage;
}).join('\n');

const digest = '*Twilio debugger digest*\n' +
  'Total alerts: ' + alerts.length + '\n' +
  'Severity: ' + (severityLine || 'none') + '\n' +
  'Distinct groups: ' + grouped.length + '\n\n' +
  'Top error codes:\n' + (topLines || '- none');

return rows.map(function (row) {
  return {
    json: {
      timestamp: row.timestamp,
      errorCode: row.errorCode,
      logLevel: row.logLevel,
      resourceSid: row.resourceSid,
      requestUrl: row.requestUrl,
      alertSid: row.alertSid,
      totalAlerts: alerts.length,
      distinctGroups: grouped.length,
      severityBreakdown: severityLine,
      digest: digest
    }
  };
});
